const EPS=1e-9;export const CURRENCY_UNITS=Object.freeze([{value:100,label:"$100"},{value:50,label:"$50"},{value:20,label:"$20"},{value:10,label:"$10"},{value:5,label:"$5"},{value:2,label:"$2"},{value:1,label:"$1"},{value:.25,label:"Quarter"},{value:.1,label:"Dime"},{value:.05,label:"Nickel"},{value:.01,label:"Penny"}]);export function parseInput(e){if(!e||"string"!=typeof e)return null;const a=e.trim();let l;if(a.includes(" "))l=a.split(/\s+/);else if(a.includes("+"))l=a.split("+");else{if(!a.includes(","))return null;l=a.split(",")}if(l.length<2)return null;const t=parseFloat(l[0]),n=parseFloat(l[1]);return isNaN(t)||isNaN(n)||t<0||n<0?null:{price:Math.round(100*t)/100,paid:Math.round(100*n)/100}}export function greedy(e,a=CURRENCY_UNITS,l=1/0){let t=e;const n=[];for(const e of a){if(t<e.value-EPS)continue;const a=Math.floor(t/e.value+EPS),i=Math.min(a,l);if(i>0&&(n.push({value:e.value,label:e.label,count:i}),t=+(t-e.value*i).toFixed(2)),t<EPS)break}return{items:n,remaining:t>EPS?t:0}}const DESCRIPTIONS={optimal:"Takes the largest possible quantity per denomination from top to bottom, ensuring the minimum total pieces for fastest handover.",balanced:"Limits each denomination to 3 units max; excess spills into smaller denominations for a well-distributed mix.",practical:"Skips Penny and Nickel — fewer tiny coins, more convenient in real-world cash transactions."};export function calculate(e,a){const l=+(+e).toFixed(2),t=+(+a).toFixed(2);if(isNaN(l)||isNaN(t)||l<0||t<0)return{status:"invalid",balance:0,plans:[]};const n=+(t-l).toFixed(2);if(Math.abs(n)<EPS)return{status:"exact",balance:0,plans:[]};if(n<0)return{status:"short",balance:n,plans:[]};const i=[{id:"optimal",name:"Optimal Plan",cap:1/0,filter:null},{id:"balanced",name:"Balanced Plan",cap:3,filter:null},{id:"practical",name:"Practical Plan",cap:1/0,filter:e=>e.value>=.1}].map(e=>{const a=e.filter?CURRENCY_UNITS.filter(e.filter):CURRENCY_UNITS;let l=greedy(n,a,e.cap);if("practical"===e.id&&l.remaining>EPS){l=greedy(n,CURRENCY_UNITS)}return{id:e.id,name:e.name,totalCount:l.items.reduce((e,a)=>e+a.count,0),typeCount:l.items.length,units:l.items.map(e=>({value:e.value,label:e.label,count:e.count})),desc:DESCRIPTIONS[e.id]}});return{status:"settled",balance:n,plans:i}}